using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o => o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (IFormFileCollection files, HttpRequest request) =>
{
    // Read the description field from the same multipart form
    var description = request.Form["description"].ToString();

    if (files.Count == 0)
        return Results.BadRequest("No files uploaded.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var path = Path.Combine("uploads", file.FileName);
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);
        saved.Add(file.FileName);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery()                          // needed for bare API calls
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);

app.Run();
```

**Key points:**

- `IFormFileCollection` binds all files from the multipart form; extra text fields come from `request.Form["..."]`.
- `.WithRequestFormLimits(...)` raises the per-endpoint multipart limit to 50 MB.
- `ConfigureKestrel` raises Kestrel's overall request body limit to match.
- `.DisableAntiforgery()` lets you call it from tools like `curl` without an antiforgery token.

**Example `curl` call:**

```bash
curl -F "files=@photo1.png" -F "files=@photo2.jpg" \
     -F "description=My vacation pics" \
     http://localhost:5000/upload
```
